module top_module(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);wire [4:0] c; // Carry wires
    wire [3:0] g; // Generate signals
    wire [3:0] p; // Propagate signals

  assign cout = c[4];
  assign sum = g ^ {c[3:1], c[0]};

  assign c[4] = p[3] | (g[3] & c[3]);
  assign c[3] = p[2] | (g[2] & c[2]);
  assign c[2] = p[1] | (g[1] & c[1]);
  assign c[1] = p[0] | (g[0] & c[0]);
  assign c[0] = cin;

  assign p = a & b;
  assign g = a ^ b;

endmodule
